// Spawn Electron Dev Process
const electron = spawn(npmCmd, ['run', 'electron:dev'], { stdio: 'inherit' });

[vite, electron].forEach(proc => {
    proc.on('close', code => {
        if (code !== 0 && code !== null) {
            console.error(`Process exited with code ${code}`);
        }
        process.exit(code || 0);
    });
});

