// electron/bridge.js
import express from 'express';
import cors from 'cors';
import { exec, execSync, spawn } from 'child_process';
import { fileURLToPath } from 'url';
import path from 'path';
import fs from 'fs';
import os from 'os';
import { initStore, getConfig, setConfig, getHistory, appendHistory, clearHistory } from './store.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const LOCAL_OLLAMA_PATH = path.join(os.homedir(), 'AppData', 'Local', 'Programs', 'Ollama', 'ollama.exe');

// ── Active project state ─────────────────────────────────────
// Mutated when the IDE calls /analyze with a projectPath.
// Deliberately module-level so every endpoint can read it.
let activeProjectPath = null;

export function startBridge(mainWindow, userDataPath) {
    if (userDataPath) initStore(userDataPath);

    const app = express();
    const PORT = 9090;

    app.use(cors());
    app.use(express.json({ limit: '5mb' }));

    // ── IDE Analyze Endpoint ─────────────────────────────────
    // Accepts: { code, file, projectPath? }
    // projectPath is the absolute root of the user's project so
    // subsequent /git/diff calls run against THEIR repo, not ours.
    app.post('/analyze', (req, res) => {
        const { code, file, projectPath } = req.body;

        // Update active project whenever the IDE sends a new one
        if (projectPath && typeof projectPath === 'string' && projectPath.trim()) {
            activeProjectPath = projectPath.trim();
            console.log(`[BRIDGE] Active project set to: ${activeProjectPath}`);
        }

        console.log(`[BRIDGE] Analysis request — file: ${file} | project: ${activeProjectPath ?? 'unknown'}`);

        if (mainWindow) {
            mainWindow.webContents.send('ide-trigger', {
                type: 'ANALYZE',
                payload: { code, file, projectPath: activeProjectPath },
            });
            if (mainWindow.isMinimized()) mainWindow.restore();
            mainWindow.focus();
        }

        res.json({ status: 'processing', message: 'ShadowDeck activated' });
    });

    // ── Git Diff Endpoint ────────────────────────────────────
    // Safety: Buffer array collection + 10 MB hard cap to prevent
    // memory exhaustion on large repos (root cause of HERALD crash).

    const MAX_DIFF_BYTES = 10 * 1024 * 1024; // 10 MB

    app.post('/git/diff', (req, res) => {
        const cwd = req.body?.projectPath || activeProjectPath || path.resolve(__dirname, '..');
        const git = spawn('git', ['diff', 'HEAD'], { cwd });

        const chunks = [];
        let totalBytes = 0;
        let killed = false;
        let stderr = '';

        git.stdout.on('data', (data) => {
            totalBytes += data.length;
            if (totalBytes > MAX_DIFF_BYTES) {
                if (!killed) {
                    killed = true;
                    git.kill('SIGTERM');
                    console.warn(`[BRIDGE] ⚠️  git diff exceeded ${MAX_DIFF_BYTES / 1024 / 1024}MB — killed.`);
                }
                return;
            }
            chunks.push(data);
        });

        git.stderr.on('data', (data) => { stderr += data; });

        git.on('error', (err) => {
            console.error(`[BRIDGE] git spawn error: ${err.message}`);
            if (!res.headersSent) {
                res.status(500).json({ diff: '', error: `Git spawn failed: ${err.message}` });
            }
        });

        git.on('close', (code) => {
            if (res.headersSent) return;
            if (code !== 0 && !killed) return res.json({ diff: '', error: stderr });

            let diff = Buffer.concat(chunks).toString('utf-8').trim();
            const actualDiffBytes = Buffer.byteLength(diff);

            // ── Append Untracked Files ──
            if (!killed && actualDiffBytes < MAX_DIFF_BYTES) {
                try {
                    // Find all untracked files
                    const lsFiles = execSync('git ls-files --others --exclude-standard', { cwd, encoding: 'utf-8' });
                    const untrackedFiles = lsFiles.split('\n').map(f => f.trim()).filter(Boolean);

                    // Skip high-noise files that bloat the diff without providing much "code change" value
                    const NOISE_FILES = new Set(['package-lock.json', 'yarn.lock', 'pnpm-lock.yaml', 'bun.lockb']);

                    let untrackedBytes = 0;
                    // Cap the total *untracked* addition bytes to 5MB now that we have Swarm
                    const maxUntrackedBytes = 5 * 1024 * 1024;

                    for (let i = 0; i < untrackedFiles.length; i++) {
                        const file = untrackedFiles[i];
                        if (NOISE_FILES.has(path.basename(file))) continue;

                        try {
                            const absPath = path.join(cwd, file);
                            const stat = fs.statSync(absPath);
                            if (!stat.isFile()) continue;

                            // 256KB cap per untracked file to prevent huge binaries from saturating the diff
                            const content = fs.readFileSync(absPath, 'utf-8').slice(0, 256 * 1024);

                            const addition = `\n\n--- UNTRACKED FILE: ${file} ---\n${content}`;

                            if (untrackedBytes + Buffer.byteLength(addition) > maxUntrackedBytes) {
                                diff += `\n\n[WARNING: ${untrackedFiles.length - i} more untracked files omitted to preserve context window]`;
                                break;
                            }

                            if (Buffer.byteLength(diff) + Buffer.byteLength(addition) > MAX_DIFF_BYTES) {
                                diff += `\n\n[WARNING: Additional untracked files omitted due to size limits]`;
                                killed = true;
                                break;
                            }

                            diff += addition;
                            untrackedBytes += Buffer.byteLength(addition);
                        } catch (err) {
                            // Ignore individual file read errors
                        }
                    }
                } catch (err) {
                    console.error(`[BRIDGE] Failed to get untracked files: ${err.message}`);
                }
            }

            res.json({
                diff,
                cwd,
                truncated: killed,
                ...(killed && { warning: `Diff exceeded ${MAX_DIFF_BYTES / 1024 / 1024}MB and was truncated.` }),
            });
        });
    });

    // ── Project Connect (manual) ────────────────────────────
    // Accepts { path } and validates it as a directory.
    app.post('/project/connect', (req, res) => {
        const dirPath = req.body?.path;
        if (!dirPath || typeof dirPath !== 'string') {
            return res.status(400).json({ error: 'Missing or invalid path' });
        }
        try {
            const stat = fs.statSync(dirPath.trim());
            if (!stat.isDirectory()) {
                return res.status(400).json({ error: 'Path is not a directory' });
            }
            activeProjectPath = dirPath.trim();
            console.log(`[BRIDGE] Project connected (manual): ${activeProjectPath}`);
            res.json({ status: 'connected', path: activeProjectPath });
        } catch (err) {
            console.error(`[BRIDGE] Project connect error: ${err.message}`);
            res.status(400).json({ error: `Invalid path: ${err.message}` });
        }
    });

    app.get('/project/active', (_req, res) => {
        res.json({ path: activeProjectPath });
    });

    // ── Read a single project file ──────────────────────────
    // GET /project/file?rel=<relative-path>
    // Returns raw file contents (capped at 500 KB).
    const MAX_FILE_BYTES = 500 * 1024;
    app.get('/project/file', (req, res) => {
        if (!activeProjectPath) return res.status(400).json({ error: 'No project connected' });
        const rel = req.query.rel;
        if (!rel) return res.status(400).json({ error: 'Missing ?rel= parameter' });

        const absPath = path.resolve(activeProjectPath, rel);
        // Path traversal guard
        if (!absPath.startsWith(path.resolve(activeProjectPath))) {
            return res.status(403).json({ error: 'Path traversal rejected' });
        }

        try {
            const stat = fs.statSync(absPath);
            if (!stat.isFile()) return res.status(400).json({ error: 'Not a file' });
            if (stat.size > MAX_FILE_BYTES) {
                return res.json({ content: fs.readFileSync(absPath, 'utf-8').slice(0, MAX_FILE_BYTES), truncated: true });
            }
            res.json({ content: fs.readFileSync(absPath, 'utf-8'), truncated: false });
        } catch (err) {
            res.status(404).json({ error: `File not found: ${err.message}` });
        }
    });

    // ── Project file tree ───────────────────────────────────
    // GET /project/tree
    // Returns a flat list of files (max 3 levels, excludes node_modules/.git, capped at 500 entries).
    app.get('/project/tree', (_req, res) => {
        if (!activeProjectPath) return res.status(400).json({ error: 'No project connected' });

        const SKIP = new Set(['node_modules', '.git', 'dist', 'build', '.next', '__pycache__', '.venv', 'venv']);
        const MAX_ENTRIES = 500;
        const entries = [];

        function walk(dir, depth) {
            if (depth > 3 || entries.length >= MAX_ENTRIES) return;
            let items;
            try { items = fs.readdirSync(dir, { withFileTypes: true }); } catch { return; }
            for (const item of items) {
                if (SKIP.has(item.name) || item.name.startsWith('.')) continue;
                const rel = path.relative(activeProjectPath, path.join(dir, item.name)).replace(/\\/g, '/');
                entries.push({ name: rel, type: item.isDirectory() ? 'dir' : 'file' });
                if (entries.length >= MAX_ENTRIES) return;
                if (item.isDirectory()) walk(path.join(dir, item.name), depth + 1);
            }
        }

        walk(activeProjectPath, 0);
        res.json({ root: activeProjectPath, entries, truncated: entries.length >= MAX_ENTRIES });
    });

    // ── Store: Config ────────────────────────────────────────
    app.get('/store/config', (_req, res) => res.json(getConfig()));
    app.post('/store/config', (req, res) => res.json(setConfig(req.body)));

    // ── Store: History ───────────────────────────────────────
    app.get('/store/history', (_req, res) => res.json(getHistory()));
    app.post('/store/history', (req, res) => res.json(appendHistory(req.body)));
    app.delete('/store/history', (_req, res) => { clearHistory(); res.json({ ok: true }); });

    // ── Ollama AI Proxy (Streaming) ──────────────────────────
    app.post('/ai/generate', async (req, res) => {
        try {
            const isChat = !!req.body.messages;
            const endpoint = isChat ? 'http://localhost:11434/api/chat' : 'http://localhost:11434/api/generate';

            const ollamaRes = await fetch(endpoint, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(req.body),
            });

            if (!ollamaRes.ok) {
                const errText = await ollamaRes.text();
                console.error(`[BRIDGE] Ollama error ${ollamaRes.status}: ${errText}`);
                return res.status(ollamaRes.status).json({ error: errText });
            }

            res.setHeader('Content-Type', 'application/x-ndjson');
            res.setHeader('Transfer-Encoding', 'chunked');

            const reader = ollamaRes.body.getReader();
            const decoder = new TextDecoder();
            while (true) {
                const { done, value } = await reader.read();
                if (done) break;
                res.write(decoder.decode(value, { stream: true }));
            }
            res.end();
        } catch (err) {
            console.error(`[BRIDGE] Ollama proxy error: ${err.message}`);
            res.status(502).json({ error: `Ollama unreachable: ${err.message}` });
        }
    });

    // ── Start Server ─────────────────────────────────────────
    app.listen(PORT, () => {
        console.log(`🔌 ShadowDeck Bridge listening on http://localhost:${PORT}`);

        exec('ollama list', (error, stdout) => {
            if (!error && stdout) {
                console.log('[BRIDGE] 🧠 Ollama Models (via CLI):');
                stdout.trim().split('\n').forEach(line => console.log(`  ${line}`));
                return;
            }
            if (fs.existsSync(LOCAL_OLLAMA_PATH)) {
                console.log(`[BRIDGE] 🟢 Ollama at: ${LOCAL_OLLAMA_PATH}`);
                exec(`"${LOCAL_OLLAMA_PATH}" list`, (err2, stdout2) => {
                    if (!err2 && stdout2) {
                        console.log('[BRIDGE] 🧠 Models:');
                        stdout2.trim().split('\n').forEach(l => console.log(`  ${l}`));
                    }
                });
                return;
            }
            fetch('http://localhost:11434/api/tags')
                .then(r => r.json())
                .then(data => {
                    console.log('[BRIDGE] 🟢 Ollama API active.');
                    data.models?.forEach(m => console.log(`  ${m.name}`));
                })
                .catch(() => {
                    console.warn('[BRIDGE] ⚠️  Ollama not found. Run "npm run setup".');
                });
        });
    });
}

